# domains/users/router.py
from fastapi import APIRouter, Depends, HTTPException, status
from sqlalchemy.ext.asyncio import AsyncSession

from database import get_db
from domains.users.schemas import UserCreate, UserResponse, UserUpdate
from domains.users.service import UserService
from domains.users.dependencies import get_user_service
from core.security import get_current_user

router = APIRouter(
    prefix="/users",          # All routes get this prefix
    tags=["Users"],           # OpenAPI tag for grouping in docs
    dependencies=[Depends(get_current_user)],  # Applied to all routes in router
    responses={
        401: {"description": "Unauthorized"},
        403: {"description": "Forbidden"},
    }
)

@router.get("/", response_model=list[UserResponse])
async def list_users(
    skip: int = 0,
    limit: int = 20,
    service: UserService = Depends(get_user_service)
):
    return await service.list_users(skip=skip, limit=limit)

@router.get("/{user_id}", response_model=UserResponse)
async def get_user(
    user_id: int,
    service: UserService = Depends(get_user_service)
):
    user = await service.get_by_id(user_id)
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    return user

@router.post("/", response_model=UserResponse, status_code=status.HTTP_201_CREATED)
async def create_user(
    user_data: UserCreate,
    service: UserService = Depends(get_user_service)
):
    return await service.create_user(user_data)

@router.patch("/{user_id}", response_model=UserResponse)
async def update_user(
    user_id: int,
    update_data: UserUpdate,
    service: UserService = Depends(get_user_service),
    current_user = Depends(get_current_user)
):
    if current_user.id != user_id and "admin" not in current_user.roles:
        raise HTTPException(status_code=403, detail="Insufficient permissions")
    user = await service.update_user(user_id, update_data)
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    return user

