from typing import Optional
from fastapi import HTTPException, status
from passlib.context import CryptContext

from domains.users.repository import UserRepository
from domains.users.schemas import UserCreate, UserUpdate
from domains.users.models import User

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")

class UserService:
    def __init__(self, repository: UserRepository):
        self.repository = repository

    async def get_by_id(self, user_id: int) -> Optional[User]:
        return await self.repository.get_by_id(user_id)

    async def get_by_email(self, email: str) -> Optional[User]:
        return await self.repository.get_by_email(email)

    async def list_users(self, skip: int = 0, limit: int = 20) -> list[User]:
        return await self.repository.list_active(skip=skip, limit=limit)

    async def create_user(self, user_data: UserCreate) -> User:
        # Business rule: email must be unique
        existing = await self.repository.get_by_email(user_data.email)
        if existing:
            raise HTTPException(
                status_code=status.HTTP_409_CONFLICT,
                detail="Email address already registered"
            )

        # Business rule: hash password before persistence
        hashed = pwd_context.hash(user_data.password)
        return await self.repository.create(
            username=user_data.username,
            email=user_data.email,
            hashed_password=hashed
        )

    async def update_user(self, user_id: int, update_data: UserUpdate) -> Optional[User]:
        user = await self.repository.get_by_id(user_id)
        if not user:
            return None

        # Business rule: if changing email, check uniqueness
        if update_data.email and update_data.email != user.email:
            existing = await self.repository.get_by_email(update_data.email)
            if existing:
                raise HTTPException(
                    status_code=status.HTTP_409_CONFLICT,
                    detail="Email address already in use"
                )

        update_dict = update_data.model_dump(exclude_unset=True)
        if "password" in update_dict:
            update_dict["hashed_password"] = pwd_context.hash(update_dict.pop("password"))

        return await self.repository.update(user_id, update_dict)

    async def deactivate_user(self, user_id: int) -> bool:
        user = await self.repository.get_by_id(user_id)
        if not user:
            return False
        await self.repository.update(user_id, {"is_active": False})
        return True

    def verify_password(self, plain: str, hashed: str) -> bool:
        return pwd_context.verify(plain, hashed)

