from fastapi import HTTPException, Request, status
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError
from pydantic import ValidationError

class DomainException(Exception):
    """Base for all domain-level exceptions."""
    def __init__(self, message: str, code: str = "DOMAIN_ERROR"):
        self.message = message
        self.code = code
        super().__init__(message)

class ResourceNotFound(DomainException):
    def __init__(self, resource: str, resource_id):
        super().__init__(
            message=f"{resource} with id '{resource_id}' not found",
            code="RESOURCE_NOT_FOUND"
        )

class ResourceConflict(DomainException):
    def __init__(self, message: str):
        super().__init__(message=message, code="RESOURCE_CONFLICT")

class InsufficientPermissions(DomainException):
    def __init__(self, action: str):
        super().__init__(
            message=f"Insufficient permissions to perform: {action}",
            code="INSUFFICIENT_PERMISSIONS"
        )

# Register handlers on the app
def setup_exception_handlers(app):
    @app.exception_handler(ResourceNotFound)
    async def not_found_handler(request: Request, exc: ResourceNotFound):
        return JSONResponse(
            status_code=status.HTTP_404_NOT_FOUND,
            content={"error": exc.code, "detail": exc.message}
        )

    @app.exception_handler(ResourceConflict)
    async def conflict_handler(request: Request, exc: ResourceConflict):
        return JSONResponse(
            status_code=status.HTTP_409_CONFLICT,
            content={"error": exc.code, "detail": exc.message}
        )

    @app.exception_handler(InsufficientPermissions)
    async def permission_handler(request: Request, exc: InsufficientPermissions):
        return JSONResponse(
            status_code=status.HTTP_403_FORBIDDEN,
            content={"error": exc.code, "detail": exc.message}
        )

    @app.exception_handler(RequestValidationError)
    async def validation_handler(request: Request, exc: RequestValidationError):
        return JSONResponse(
            status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            content={
                "error": "VALIDATION_ERROR",
                "detail": "Request validation failed",
                "fields": [
                    {
                        "field": ".".join(str(loc) for loc in err["loc"]),
                        "message": err["msg"],
                        "type": err["type"]
                    }
                    for err in exc.errors()
                ]
            }
        )

    @app.exception_handler(Exception)
    async def generic_handler(request: Request, exc: Exception):
        import logging
        logging.exception(f"Unhandled exception on {request.url.path}")
        return JSONResponse(
            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            content={"error": "INTERNAL_ERROR", "detail": "An unexpected error occurred"}
        )

